/**
 * @summary Toggle bookmark on a news item
 */
export const getToggleBookmarkUrl = (id: number) => {
  return `/api/news/${id}/bookmark`;
};

export const toggleBookmark = async (
  id: number,
  options?: RequestInit,
): Promise<BookmarkResponse> => {
  return customFetch<BookmarkResponse>(getToggleBookmarkUrl(id), {
    ...options,
    method: "POST",
  });
};

export const getToggleBookmarkMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof toggleBookmark>>,
    TError,
    { id: number },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof toggleBookmark>>,
  TError,
  { id: number },
  TContext
> => {
  const mutationKey = ["toggleBookmark"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof toggleBookmark>>,
    { id: number }
  > = (props) => {
    const { id } = props ?? {};

    return toggleBookmark(id, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type ToggleBookmarkMutationResult = NonNullable<
  Awaited<ReturnType<typeof toggleBookmark>>
>;

export type ToggleBookmarkMutationError = ErrorType<unknown>;

